import sysfrom pathlib import Pathimport jsonfrom typing import Any, Dict, List, Optionalimport pandas as pdimport pyarrow as paimport pyarrow.parquet as pqfrom datasets import load_dataset# Ensure project root is on sys.pathPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import PROCESSED_DATA_DIRDATASET_NAME = "JanosAudran/financial-reports-sec"DATASET_CONFIG = "large_lite"LABEL_WINDOW = "5d"SPLITS = ["train", "validation", "test"]# Write every N completed documentsDOC_BATCH_SIZE = 1000def extract_label(label_obj: Any, window: str = LABEL_WINDOW) -> Optional[int]:    if not isinstance(label_obj, dict):        return None    value = label_obj.get(window, None)    if value is None:        return None    try:        return int(value)    except Exception:        return Nonedef finalize_doc(doc: Dict[str, Any]) -> Dict[str, Any]:    section_list = list(dict.fromkeys(doc["section_list"]))    return {        "docID": doc["docID"],        "cik": doc["cik"],        "filingDate": doc["filingDate"],        "full_text": " ".join(doc["sentences"]),        "label_5d": doc["label_5d"],        "section_list": json.dumps(section_list),        "n_sections": len(section_list),        "n_sentences": len(doc["sentences"]),    }def write_batch(rows: List[Dict[str, Any]], writer: Optional[pq.ParquetWriter], out_path_tmp: Path):    if not rows:        return writer    table = pa.Table.from_pandas(pd.DataFrame(rows), preserve_index=False)    if writer is None:        writer = pq.ParquetWriter(out_path_tmp, table.schema)    writer.write_table(table)    return writerdef process_split(split_name: str):    PROCESSED_DATA_DIR.mkdir(parents=True, exist_ok=True)    out_path = PROCESSED_DATA_DIR / f"{split_name}_doc_{LABEL_WINDOW}_{DATASET_CONFIG}.parquet"    out_path_tmp = PROCESSED_DATA_DIR / f"{split_name}_doc_{LABEL_WINDOW}_{DATASET_CONFIG}.tmp.parquet"    if out_path_tmp.exists():        out_path_tmp.unlink()    print("\n====================================================")    print(f"Processing split: {split_name}")    print(f"Output file: {out_path}")    print("This step can take a while for large_lite, especially train.")    print("Please keep the laptop plugged in and avoid sleep/shutdown.")    print("====================================================\n")    ds = load_dataset(        DATASET_NAME,        DATASET_CONFIG,        split=split_name,        streaming=True,    )    writer = None    rows_buffer: List[Dict[str, Any]] = []    current_doc = None    current_doc_id = None    seen_doc_ids = set()    n_examples = 0    n_docs = 0    for ex in ds:        n_examples += 1        doc_id = ex["docID"]        if current_doc_id is None:            current_doc_id = doc_id            current_doc = {                "docID": ex["docID"],                "cik": ex.get("cik"),                "filingDate": ex.get("filingDate"),                "label_5d": extract_label(ex.get("labels")),                "sentences": [str(ex.get("sentence", ""))],                "section_list": [str(ex.get("section"))],            }        elif doc_id == current_doc_id:            current_doc["sentences"].append(str(ex.get("sentence", "")))            current_doc["section_list"].append(str(ex.get("section")))        else:            if current_doc_id in seen_doc_ids:                raise RuntimeError(                    f"docID {current_doc_id} appeared again after being finalized. "                    "This breaks the streaming aggregation assumption."                )            seen_doc_ids.add(current_doc_id)            row = finalize_doc(current_doc)            rows_buffer.append(row)            n_docs += 1            if n_docs % DOC_BATCH_SIZE == 0:                writer = write_batch(rows_buffer, writer, out_path_tmp)                rows_buffer = []                print(f"[{split_name}] processed docs: {n_docs:,} | seen sentences: {n_examples:,}")            current_doc_id = doc_id            current_doc = {                "docID": ex["docID"],                "cik": ex.get("cik"),                "filingDate": ex.get("filingDate"),                "label_5d": extract_label(ex.get("labels")),                "sentences": [str(ex.get("sentence", ""))],                "section_list": [str(ex.get("section"))],            }    if current_doc is not None:        row = finalize_doc(current_doc)        rows_buffer.append(row)        n_docs += 1    writer = write_batch(rows_buffer, writer, out_path_tmp)    rows_buffer = []    if writer is not None:        writer.close()    if out_path.exists():        out_path.unlink()    out_path_tmp.rename(out_path)    print(f"\nFinished split: {split_name}")    print(f"Total streamed sentences: {n_examples:,}")    print(f"Total document rows:      {n_docs:,}")    print(f"Saved to: {out_path}\n")def main():    for split_name in SPLITS:        process_split(split_name)    print("\nAll large_lite document-level files created successfully.")if __name__ == "__main__":    main()